from collections import Counter

class Solution:
    def checkInclusion(self, s1, s2):
        need = Counter(s1)
        window = Counter()
        size = len(s1)
        for i, ch in enumerate(s2):
            window[ch] += 1
            if i >= size:
                old = s2[i - size]
                window[old] -= 1
                if window[old] == 0:
                    del window[old]
            if i >= size - 1 and window == need:
                return True
        return False
